  ('diplomatic-0248a032-moex-00067', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '下列何種案件得於總統在位期間，將其列為犯罪嫌疑人，並開啟偵查程序？', '["總統涉嫌傷害", "總統涉嫌貪污", "總統涉嫌毀謗", "總統涉嫌外患"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00068', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '有關憲法訴訟法所定之各聲請主體及要件，下列敘述何者正確？', '["總統得以其行使職權，適用憲法發生疑義為由，聲請憲法法庭判決", "現有總額三分之一以上之立法委員，得以其行使職權，適用憲法發生疑義為由，聲請憲法法庭判決", "地方自治行政機關如認有關非地方自治事項所應適用之法規範違憲，報請上級機關聲請憲法法庭判決", "懲戒法院法官於其審理中之案件，認應適用之命令違憲，得聲請憲法法庭判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00069', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '下列何者不是司法院之職權？', '["民、刑事及行政訴訟之審判", "犯罪偵查", "公務員懲戒", "審理政黨違憲之解散事項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00070', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '依臺灣地區與大陸地區人民關係條例第 65 條第 1 款規定：「臺灣地區人民收養大陸地區人民為養子 女，……有下列情形之一者，法院亦應不予認可：一、已有子女或養子女者。」依司法院大法官解釋， 此一規定是否合憲？', '["合憲，因為憲法並未保障收養自由，收養對象之規定純屬立法裁量", "違憲，因臺灣地區人民收養其配偶之大陸地區子女，法院亦應不予認可部分，有違憲法第22條保 障收養自由之意旨", "合憲，因本法涉及兩岸關係，為司法不應解釋之政治問題", "違憲，因臺灣地區人民收養其他國家、地區人民為養子女，並無此等限制，系爭規定違反憲法第7 條平等權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
