  ('diplomatic-0248a032-moex-00072', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-114-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '依立法院的組織與運作之規定，下列敘述何者錯誤？', '["立法院設院長、副院長各一人，由立法委員互選產生", "立法院院長、副院長不得擔任政黨職務，應本公平中立原則行使職權，維持立法院秩序，處理議事", "立法院會議，應公開舉行，不得開秘密會議", "立法院臨時會，以決議召集臨時會之特定事項為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:54+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
